--! cl_fix_max_value implementation	
function cl_fix_max_value (	fmt 	: FixFormat_t) 
							return std_logic_vector is
	variable result_v : std_logic_vector (cl_fix_width (fmt)-1 downto 0);
begin
	result_v := (others => '1');
	if fmt.Signed then
		result_v (result_v'high) := '0';
	end if;
	return result_v;
end;

